async function getTextBinary(itemIndex, item, propertyName, expectedFileName) {
  const binary = item.binary?.[propertyName];
  if (!binary) {
    throw new Error(`Missing binary property '${propertyName}'.`);
  }

  const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
  return {
    fileName: binary.fileName || expectedFileName,
    content: buffer.toString('utf8'),
  };
}

