  const requirements = await getTextBinary.call(this, itemIndex, item, 'requirements', 'requirements.md');
  const designApi = await getTextBinary.call(this, itemIndex, item, 'design_api', 'design_api.json');

  const userPrompt = [
    'Here are the two input artefacts.',
    '',
