function extractOpenApiYaml(rawText) {
  if (typeof rawText !== "string" || !rawText.trim()) {
    throw new Error("Model output is empty.");
  }

  let text = rawText.trim();

  const fencedMatch = text.match(/```(?:yaml|yml)?\s*([\s\S]*?)```/i);
  if (fencedMatch) {
    text = fencedMatch[1].trim();
  }

  const openapiMatch = text.match(/(?:^|\n)(openapi:\s*[\s\S]*)/i);
  if (openapiMatch) {
    text = openapiMatch[1].trim();
  }

  const trailingMarkers = [
    /\nThis OpenAPI specification/i,
    /\nThis specification/i,
    /\nKey features include:/i,
    /\nThe specification is ready/i,
    /\nAll endpoints follow/i,
  ];

  let endIndex = text.length;
  for (const marker of trailingMarkers) {
    const match = marker.exec(text);
    if (match && match.index > 0) endIndex = Math.min(endIndex, match.index);
  }

  text = text.slice(0, endIndex).trim();
  if (!/^openapi:\s*/i.test(text)) {
    throw new Error("Could not find an OpenAPI YAML document in model output.");
  }

  return text;
}

function joinContentBlocks(value) {
  if (!Array.isArray(value)) return "";
  const parts = value
    .map((entry) => {
      if (typeof entry === "string") return entry;
      if (entry && typeof entry.text === "string") return entry.text;
      if (entry && typeof entry.content === "string") return entry.content;
      return "";
    })
    .filter((entry) => entry && entry.trim());
  return parts.join("\n").trim();
}

function toTokenCount(value) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed < 0) return null;
  return Math.trunc(parsed);
}

function extractUsageTokensObject(obj) {
